
  // ── NAV SCROLL ──
  window.addEventListener('scroll', () => {
    document.getElementById('mainNav').classList.toggle('scrolled', window.scrollY > 40);
  });

  // ── SCROLL TO SECTION ──
  function scrollTo(id) {
    setTimeout(() => {
      const el = document.getElementById(id);
      if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  }

  // ── FAQ TOGGLE ──
  function toggleFaq(el) {
    el.classList.toggle('open');
  }

  // ── CLOSE MODAL ──
  function closeModal(e) {
    if (!e || e.target === document.getElementById('videoModal') || e.currentTarget.tagName === 'BUTTON') {
      document.getElementById('videoModal').classList.remove('open');
      document.getElementById('modalIframe').src = '';
    }
  }

  // ── OPEN VIDEO MODAL ──
  function openVideo(youtubeId) {
    document.getElementById('modalIframe').src = 'https://www.youtube.com/embed/' + youtubeId + '?autoplay=1';
    document.getElementById('videoModal').classList.add('open');
  }

  // ── PAGE SWITCHING ──
  const pageNavMap = { work: 'workNavLink', log: 'logNavLink', registry: 'registryNavLink', brief: 'briefNavLink', about: 'aboutNavLink' };

  function showPage(page) {
    document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
    var el = document.getElementById(page + '-page');
    if (el) el.classList.add('active');
    window.scrollTo(0, 0);
    Object.values(pageNavMap).forEach(function(id) {
      var a = document.getElementById(id);
      if (a) a.style.color = '';
    });
    if (pageNavMap[page]) {
      var a = document.getElementById(pageNavMap[page]);
      if (a) a.style.color = 'var(--accent)';
    }
  }

