  // ── BRIEF FORM SUBMIT ──
  function submitBrief() {
    var form = document.getElementById('briefForm');
    var company = form.querySelector('[name=company]').value.trim();
    var contact = form.querySelector('[name=contact_name]').value.trim();
    var email = form.querySelector('[name=email]').value.trim();
    var website = form.querySelector('[name=website]').value.trim();
    var ptype = form.querySelector('[name=project_type]').value;
    var desc = form.querySelector('[name=description]').value.trim();
    var primary = form.querySelector('[name=primary_audience]').value.trim();
    var secondary = form.querySelector('[name=secondary_audience]').value.trim();
    var message = form.querySelector('[name=key_message]').value.trim();
    var budget = form.querySelector('[name=budget]').value;
    var timeline = form.querySelector('[name=timeline]').value.trim();
    var guidelines = form.querySelector('[name=brand_guidelines]').value;
    var avoid = form.querySelector('[name=avoid]').value.trim();
    var other = form.querySelector('[name=other]').value.trim();

    // Get checked platforms
    var platforms = [];
    form.querySelectorAll('[name=platform]:checked').forEach(function(cb) { platforms.push(cb.value); });

    // Validate required
    if (!company || !contact || !email || !ptype || !desc || !primary || !message || !budget || !timeline) {
      alert('Please complete all required fields before submitting.');
      return;
    }

    var body = 'MIRAI LABO — PROJECT BRIEF' +
      '\n' + '='.repeat(50) +
      '\n\n01 — WHO YOU ARE' +
      '\nCompany / Brand: ' + company +
      '\nContact Name & Role: ' + contact +
      '\nEmail: ' + email +
      (website ? '\nWebsite: ' + website : '') +
      '\n\n02 — THE PROJECT' +
      '\nProject Type: ' + ptype +
      '\n\nProject Description:\n' + desc +
      '\n\nPrimary Target Audience:\n' + primary +
      (secondary ? '\n\nSecondary Target Audience:\n' + secondary : '') +
      '\n\nKey Message:\n' + message +
      '\n\n03 — CONSTRAINTS' +
      '\nBudget Range: ' + budget +
      '\nDelivery Timeline: ' + timeline +
      '\nPlatforms: ' + (platforms.length ? platforms.join(', ') : 'Not specified') +
      '\n\n04 — CONTEXT' +
      '\nBrand Guidelines: ' + (guidelines || 'Not specified') +
      (avoid ? '\n\nWhat to Avoid:\n' + avoid : '') +
      (other ? '\n\nAdditional Context:\n' + other : '') +
      '\n\n' + '='.repeat(50) +
      '\nSubmitted via roninr9.net';

    var subject = 'Project Brief — ' + company + ' [' + ptype + ']';
    var mailto = 'mailto:bryan.lee@roninr9.net?subject=' + encodeURIComponent(subject) + '&body=' + encodeURIComponent(body);
    window.location.href = mailto;
  }

    // ── RENDER GRID ──
  function renderGrid() {
    const grid = document.getElementById('videoGrid');
    grid.innerHTML = videos.map(v => {
      const hasReal = !v.id.startsWith('placeholder');
      const thumb = hasReal
        ? '<img src="https://img.youtube.com/vi/' + v.id + '/mqdefault.jpg" loading="lazy" alt="' + v.title + ' — MIRAI Labo" style="width:100%;height:100%;object-fit:cover;position:absolute;inset:0;">'
        : '<div style="width:100%;height:100%;background:var(--deep);display:flex;align-items:center;justify-content:center;position:absolute;inset:0;"><span style="font-family:var(--display);font-size:11px;letter-spacing:0.2em;color:var(--white-ghost);text-transform:uppercase;">Coming Soon</span></div>';
      return '<div class="video-card" onclick="' + (hasReal ? 'openVideo(\'' + v.id + '\')' : '') + '">'
        + '<div class="video-thumb">'
        + thumb
        + '<div class="thumb-overlay"><div class="thumb-play">&#9654;</div></div>'
        + '</div>'
        + '<div class="video-info">'
        + '<div class="video-title">' + v.title + '</div>'
        + '<div class="video-cat">' + v.category + '</div>'
        + '</div>'
        + '</div>';
    }).join('');
  }

  renderGrid();
